"""Shared helpers for the axis runner scripts."""
from __future__ import annotations

import json
import statistics
from pathlib import Path

from . import config
from .deliverable import Bundle


def load_task(task_folder: str) -> dict:
    return json.loads((config.DATA / task_folder / "task.json").read_text())


def has_gold(task_folder: str) -> bool:
    return bool(load_task(task_folder).get("deliverable_files"))


def reference_dir(task_folder: str) -> Path:
    return config.DATA / task_folder / "reference_files"


def gold_bundle(task_folder: str) -> Bundle:
    return Bundle.with_references(
        "gold",
        config.DATA / task_folder / "deliverable_files",
        reference_dir(task_folder),
    )


def null_bundle(task_folder: str, variant: str, variant_dir: Path) -> Bundle:
    """Wrap a synthesized null deliverable with the same read-only reference files."""
    return Bundle.with_references(variant, variant_dir, reference_dir(task_folder))


def all_tasks() -> list[str]:
    return sorted(p.name for p in config.DATA.iterdir() if p.is_dir())


def tasks_with_gold() -> list[str]:
    return [t for t in all_tasks() if has_gold(t)]


def stdev(xs: list[float]) -> float:
    return statistics.pstdev(xs) if len(xs) > 1 else 0.0


def write_tsv(path: Path, header: list[str], rows: list[list]):
    with open(path, "w") as f:
        f.write("\t".join(header) + "\n")
        for r in rows:
            f.write("\t".join(str(x) for x in r) + "\n")
    print(f"  wrote {path.relative_to(config.ROOT)}  ({len(rows)} rows)")

"""A Bundle wraps the set of files a judge may inspect for one deliverable.

It abstracts over file type and over zip containers, so the agent tools can
refer to everything by a flat logical name (e.g. "stems.zip/lead_vocal.wav").
"""
from __future__ import annotations

import zipfile
from dataclasses import dataclass, field
from pathlib import Path

import fitz  # pymupdf

from . import config

TEXT_EXT = {".pdf", ".docx", ".txt", ".md", ".srt"}
IMAGE_EXT = {".jpg", ".jpeg", ".png", ".webp", ".gif"}
AUDIO_EXT = {".wav", ".mp3", ".m4a", ".aac", ".flac"}
VIDEO_EXT = {".mp4", ".mov", ".mkv", ".webm"}


def kind(name: str) -> str:
    ext = Path(name).suffix.lower()
    if ext in IMAGE_EXT:
        return "image"
    if ext in AUDIO_EXT:
        return "audio"
    if ext in VIDEO_EXT:
        return "video"
    if ext in TEXT_EXT:
        return "document"
    if ext == ".zip":
        return "archive"
    return "other"


@dataclass
class Bundle:
    label: str
    files: dict[str, Path] = field(default_factory=dict)  # logical name -> real path
    roles: dict[str, str] = field(default_factory=dict)   # logical name -> "deliverable"|"reference"
    _extract_dir: Path | None = None

    @classmethod
    def from_dir(cls, label: str, directory: Path, expand_zip_media: bool = True,
                 role: str = "deliverable") -> "Bundle":
        b = cls(label=label)
        b._ingest(directory, role, expand_zip_media)
        return b

    @classmethod
    def with_references(cls, label: str, deliverable_dir: Path, reference_dir: Path | None,
                        expand_zip_media: bool = True) -> "Bundle":
        """Deliverable files (graded) plus read-only reference/input files (for comparison)."""
        b = cls(label=label)
        b._ingest(deliverable_dir, "deliverable", expand_zip_media)
        if reference_dir is not None:
            b._ingest(reference_dir, "reference", expand_zip_media)
        return b

    def _ingest(self, directory: Path, role: str, expand_zip_media: bool) -> None:
        if not directory or not directory.exists():
            return
        for p in sorted(directory.iterdir()):
            if p.is_file():
                self.files[p.name] = p
                self.roles[p.name] = role
                if expand_zip_media and p.suffix.lower() == ".zip":
                    before = set(self.files)
                    self._expand_zip(p)
                    for k in set(self.files) - before:
                        self.roles[k] = role

    def _expand_zip(self, zpath: Path) -> None:
        extract_root = config.CACHE / f"zip_{zpath.stem}"
        try:
            with zipfile.ZipFile(zpath) as zf:
                for member in zf.namelist():
                    if member.endswith("/"):
                        continue
                    if kind(member) in ("audio", "video", "image", "document"):
                        target = extract_root / member
                        if not target.exists():
                            target.parent.mkdir(parents=True, exist_ok=True)
                            with zf.open(member) as src, open(target, "wb") as dst:
                                dst.write(src.read())
                        logical = f"{zpath.name}/{Path(member).name}"
                        self.files[logical] = target
        except zipfile.BadZipFile:
            pass

    # --- introspection -----------------------------------------------------
    def listing(self) -> list[dict]:
        out = []
        for name, path in self.files.items():
            out.append({
                "name": name,
                "type": kind(name),
                "role": self.roles.get(name, "deliverable"),
                "size_kb": round(path.stat().st_size / 1024, 1),
            })
        return out

    def resolve(self, name: str) -> Path:
        if name in self.files:
            return self.files[name]
        # tolerate basename-only references from the model
        for k, p in self.files.items():
            if Path(k).name == name:
                return p
        raise FileNotFoundError(f"{name} not in bundle {self.label}: {list(self.files)}")


# --- text extraction --------------------------------------------------------
def extract_text(path: Path) -> str:
    ext = path.suffix.lower()
    if ext == ".pdf":
        doc = fitz.open(path)
        parts = []
        for i, page in enumerate(doc):
            parts.append(f"--- page {i + 1} ---\n{page.get_text()}")
        return "\n".join(parts).strip() or "[PDF has no extractable text layer]"
    if ext in (".txt", ".md", ".srt"):
        return path.read_text(errors="replace")
    if ext == ".docx":
        return _docx_text(path)
    return f"[no text extractor for {ext}]"


def _docx_text(path: Path) -> str:
    import re
    import zipfile as zf
    try:
        with zf.ZipFile(path) as z:
            xml = z.read("word/document.xml").decode("utf-8", "replace")
    except Exception as e:
        return f"[docx read failed: {e}]"
    xml = re.sub(r"</w:p>", "\n", xml)
    xml = re.sub(r"<w:tab[^>]*/>", "\t", xml)
    text = re.sub(r"<[^>]+>", "", xml)
    return re.sub(r"\n{3,}", "\n\n", text).strip()


def pdf_page_png(path: Path, page: int, zoom: float = 1.6) -> str:
    import base64
    doc = fitz.open(path)
    page = max(0, min(page, doc.page_count - 1))
    pix = doc[page].get_pixmap(matrix=fitz.Matrix(zoom, zoom))
    return base64.b64encode(pix.tobytes("png")).decode()


def pdf_page_count(path: Path) -> int:
    return fitz.open(path).page_count


def file_facts(path: Path) -> dict:
    """Deterministic, non-guessable facts: extension, size, page/word counts.

    Lets the judge answer 'is it a PDF?', 'is it <= 2 pages?', 'word count'
    without inferring from a rendering."""
    facts = {
        "name": path.name,
        "extension": path.suffix.lower(),
        "type": kind(path.name),
        "size_kb": round(path.stat().st_size / 1024, 1),
    }
    if path.suffix.lower() == ".pdf":
        doc = fitz.open(path)
        facts["page_count"] = doc.page_count
        facts["word_count"] = sum(len(p.get_text().split()) for p in doc)
    elif path.suffix.lower() in (".docx", ".txt", ".md", ".srt"):
        facts["word_count"] = len(extract_text(path).split())
    return facts

"""Agent tool schemas + dispatch, gated by the judge model's modalities.

A tool returns (text_summary, media_parts):
  * text_summary  goes back as the tool-role message (OpenAI tool messages are text only)
  * media_parts   if non-empty, the harness appends them as a follow-up user message,
                  which is how images/audio actually reach a multimodal model.
"""
from __future__ import annotations

from pathlib import Path

from . import deliverable as D
from . import media
from .models import Model


def tool_schemas(model: Model) -> list[dict]:
    """The toolbox advertised to this model (only what its modalities can use)."""
    t: list[dict] = [
        {"type": "function", "function": {
            "name": "list_files",
            "description": "List every file in the deliverable (and media inside archives).",
            "parameters": {"type": "object", "properties": {}},
        }},
        {"type": "function", "function": {
            "name": "read_text",
            "description": "Extract the text of a PDF / DOCX / TXT file.",
            "parameters": {"type": "object", "properties": {
                "name": {"type": "string"}}, "required": ["name"]},
        }},
        {"type": "function", "function": {
            "name": "transcribe_audio",
            "description": "Speech-to-text transcript of an audio or video file's audio track.",
            "parameters": {"type": "object", "properties": {
                "name": {"type": "string"}}, "required": ["name"]},
        }},
        {"type": "function", "function": {
            "name": "file_facts",
            "description": ("Deterministic facts about a file: exact extension/type, size, "
                            "PDF page count, and word count. Use this for objective criteria "
                            "(is it a PDF? is it <=2 pages? word count) instead of guessing."),
            "parameters": {"type": "object", "properties": {
                "name": {"type": "string"}}, "required": ["name"]},
        }},
        {"type": "function", "function": {
            "name": "probe_media",
            "description": ("Ground-truth technical facts (ffprobe) for an audio/video file: "
                            "container, codec, exact resolution, fps, duration in seconds, "
                            "audio channels/sample rate. Use for codec/resolution/runtime criteria."),
            "parameters": {"type": "object", "properties": {
                "name": {"type": "string"}}, "required": ["name"]},
        }},
    ]
    if model.supports("image"):
        t += [
            {"type": "function", "function": {
                "name": "view_pdf_page",
                "description": "See a rendered image of one PDF page (0-indexed). Use for layout/formatting.",
                "parameters": {"type": "object", "properties": {
                    "name": {"type": "string"}, "page": {"type": "integer"}},
                    "required": ["name", "page"]},
            }},
            {"type": "function", "function": {
                "name": "view_image",
                "description": "See an image file.",
                "parameters": {"type": "object", "properties": {
                    "name": {"type": "string"}}, "required": ["name"]},
            }},
            {"type": "function", "function": {
                "name": "view_video_frames",
                "description": ("See frames from a video. By default returns one frame per "
                                "detected scene cut (distinct shots) — best for 'includes a "
                                "shot of X' and identifiable-face checks. Pass start/end "
                                "seconds to sample a specific window uniformly (e.g. to read "
                                "an on-screen text card)."),
                "parameters": {"type": "object", "properties": {
                    "name": {"type": "string"},
                    "count": {"type": "integer", "description": "max frames, 1-14"},
                    "start_seconds": {"type": "number"},
                    "end_seconds": {"type": "number"}},
                    "required": ["name"]},
            }},
        ]
    if model.supports("audio"):
        t.append({"type": "function", "function": {
            "name": "listen_audio",
            "description": "Natively listen to a clip of an audio/video file (judge timbre, mix, music, tone).",
            "parameters": {"type": "object", "properties": {
                "name": {"type": "string"},
                "start_seconds": {"type": "number"},
                "duration_seconds": {"type": "number", "description": "<=90"}},
                "required": ["name"]},
        }})

    t.append({"type": "function", "function": {
        "name": "submit_scorecard",
        "description": "Submit final per-item verdicts. Call exactly once when done inspecting.",
        "parameters": {"type": "object", "properties": {
            "scores": {"type": "array", "items": {"type": "object", "properties": {
                "id": {"type": "string", "description": "rubric_item_id"},
                "verdict": {"type": "string",
                    "enum": ["met", "unmet", "partial", "unverifiable"],
                    "description": (
                        "met = criterion clearly true (full points); unmet = clearly false "
                        "(0); partial = genuinely in between (give `awarded`); unverifiable = "
                        "CANNOT be checked from the deliverable or any tool, e.g. external "
                        "provenance like 'footage is royalty-free' or 'music from a stock "
                        "provider' with no source log in the deliverable.")},
                "awarded": {"type": "number",
                    "description": "ONLY for verdict=partial: fraction of points, 0.0-1.0"},
                "note": {"type": "string", "description": "<=14 words of justification"}},
                "required": ["id", "verdict"]}}},
            "required": ["scores"]},
    }})
    return t


def dispatch(name: str, args: dict, bundle: D.Bundle) -> tuple[str, list[dict]]:
    try:
        return _dispatch(name, args, bundle)
    except FileNotFoundError as e:
        return f"ERROR: {e}", []
    except Exception as e:  # never let a tool crash the loop
        return f"ERROR running {name}: {e}", []


def _dispatch(name: str, args: dict, bundle: D.Bundle) -> tuple[str, list[dict]]:
    if name == "list_files":
        lines = [f"- {f['name']} [{f['type']}, {f['size_kb']}KB]" for f in bundle.listing()]
        return "Files:\n" + "\n".join(lines), []

    if name == "read_text":
        path = bundle.resolve(args["name"])
        text = D.extract_text(path)
        return text[:20000], []

    if name == "transcribe_audio":
        path = bundle.resolve(args["name"])
        return "Transcript:\n" + media.transcribe(path)[:20000], []

    if name == "file_facts":
        import json as _json
        return _json.dumps(D.file_facts(bundle.resolve(args["name"])), indent=2), []

    if name == "probe_media":
        import json as _json
        return _json.dumps(media.probe(bundle.resolve(args["name"])), indent=2), []

    if name == "view_pdf_page":
        path = bundle.resolve(args["name"])
        n = D.pdf_page_count(path)
        b64 = D.pdf_page_png(path, int(args.get("page", 0)))
        return (f"Rendered page {args.get('page', 0)} of {n} (attached).",
                [_img(b64, "image/png")])

    if name == "view_image":
        path = bundle.resolve(args["name"])
        return ("Image attached.", [_img(media.b64(path), _mime(path))])

    if name == "view_video_frames":
        path = bundle.resolve(args["name"])
        count = max(1, min(14, int(args.get("count", 10))))
        start, end = args.get("start_seconds"), args.get("end_seconds")
        if start is None and end is None:
            frames = media.scene_frames(path, max_frames=count)
            how = "scene-cut"
        else:
            frames = media.video_frames(path, n=count, start=start, end=end)
            how = f"window {start}-{end}s"
        return (f"{len(frames)} {how} frames attached.", [_img(f, "image/jpeg") for f in frames])

    if name == "listen_audio":
        path = bundle.resolve(args["name"])
        start = float(args.get("start_seconds", 0.0))
        dur = min(90.0, float(args.get("duration_seconds", 60.0)))
        clip = media.audio_clip_mp3(path, start, dur)
        return (f"Audio clip {start:.0f}-{start + dur:.0f}s attached.",
                [{"type": "input_audio", "input_audio": {"data": clip, "format": "mp3"}}])

    return f"unknown tool {name}", []


def _img(b64: str, mime: str) -> dict:
    return {"type": "image_url", "image_url": {"url": f"data:{mime};base64,{b64}"}}


def _mime(path: Path) -> str:
    ext = path.suffix.lower()
    return {".png": "image/png", ".webp": "image/webp", ".gif": "image/gif"}.get(ext, "image/jpeg")

"""ffmpeg / transcription helpers, with on-disk caching to avoid repeat spend."""
from __future__ import annotations

import base64
import hashlib
import json
import subprocess
from pathlib import Path

from openai import OpenAI

from . import config

_oai = None


def _openai() -> OpenAI:
    global _oai
    if _oai is None:
        _oai = OpenAI(api_key=config.OPENAI_API_KEY)
    return _oai


def _hash(path: Path, *extra) -> str:
    h = hashlib.sha1()
    h.update(str(path).encode())
    h.update(str(path.stat().st_size).encode())
    for e in extra:
        h.update(str(e).encode())
    return h.hexdigest()[:16]


def _run(cmd: list[str]) -> None:
    subprocess.run(cmd, check=True, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)


def duration_seconds(path: Path) -> float:
    try:
        out = subprocess.run(
            ["ffprobe", "-v", "error", "-show_entries", "format=duration",
             "-of", "json", str(path)],
            check=True, capture_output=True, text=True,
        ).stdout
        return float(json.loads(out)["format"]["duration"])
    except Exception:
        return 0.0


def probe(path: Path) -> dict:
    """Deterministic media facts via ffprobe (container, codecs, resolution, fps, ...).

    This exists so the judge never has to *guess* objective technical criteria
    ('codec is H.264', 'resolution is 1920x1080', 'runtime 29.9-30.1s')."""
    try:
        out = subprocess.run(
            ["ffprobe", "-v", "error", "-show_format", "-show_streams",
             "-of", "json", str(path)],
            check=True, capture_output=True, text=True,
        ).stdout
        raw = json.loads(out)
    except Exception as e:
        return {"error": f"ffprobe failed: {e}"}
    fmt = raw.get("format", {})
    facts: dict = {
        "container": fmt.get("format_name"),
        "duration_s": round(float(fmt.get("duration", 0) or 0), 3),
        "size_bytes": int(fmt.get("size", 0) or 0),
        "bit_rate": fmt.get("bit_rate"),
        "video": [], "audio": [],
    }
    for s in raw.get("streams", []):
        if s.get("codec_type") == "video":
            num, den = (s.get("r_frame_rate", "0/1").split("/") + ["1"])[:2]
            fps = round(float(num) / float(den), 2) if float(den) else None
            facts["video"].append({
                "codec": s.get("codec_name"),
                "width": s.get("width"), "height": s.get("height"),
                "fps": fps, "pix_fmt": s.get("pix_fmt"),
            })
        elif s.get("codec_type") == "audio":
            facts["audio"].append({
                "codec": s.get("codec_name"),
                "sample_rate": s.get("sample_rate"),
                "channels": s.get("channels"),
            })
    return facts


def b64(path: Path) -> str:
    return base64.b64encode(path.read_bytes()).decode()


# --- frames ---------------------------------------------------------------
def _nonempty(paths: list[Path]) -> list[Path]:
    return [p for p in paths if p.exists() and p.stat().st_size > 0]


def video_frames(path: Path, n: int = 10, width: int = 768,
                 start: float | None = None, end: float | None = None) -> list[Path]:
    """n evenly-spaced JPEG frame files, optionally within a [start,end] window.

    Higher default resolution + count than before so on-screen text and distinct
    shots are actually legible/visible. Returns paths; the caller validates/encodes."""
    dur = duration_seconds(path) or 1.0
    a = 0.0 if start is None else max(0.0, start)
    b = dur if end is None else min(dur, end)
    if b <= a:
        b = dur
    outdir = config.CACHE / f"frames_{_hash(path, n, width, a, b)}"
    frames = sorted(outdir.glob("*.jpg")) if outdir.exists() else []
    if not frames:
        outdir.mkdir(parents=True, exist_ok=True)
        span = b - a
        for i in range(n):
            ts = a + span * (i + 0.5) / n
            out = outdir / f"{i:03d}.jpg"
            _run(["ffmpeg", "-y", "-ss", f"{ts:.2f}", "-i", str(path),
                  "-frames:v", "1", "-vf", f"scale={width}:-1", "-q:v", "3", str(out)])
        frames = sorted(outdir.glob("*.jpg"))
    return _nonempty(frames)


def scene_frames(path: Path, max_frames: int = 12, width: int = 768,
                 threshold: float = 0.25) -> list[Path]:
    """One JPEG per detected scene cut (distinct shots), capped at max_frames.

    Covers 'includes a shot of X' / face-penalty items far better than uniform
    sampling, which routinely misses whole shots in a 30s spot."""
    outdir = config.CACHE / f"scene_{_hash(path, max_frames, width, threshold)}"
    frames = sorted(outdir.glob("*.jpg")) if outdir.exists() else []
    if not frames:
        outdir.mkdir(parents=True, exist_ok=True)
        _run(["ffmpeg", "-y", "-i", str(path),
              "-vf", f"select='gt(scene,{threshold})',scale={width}:-1",
              "-vsync", "vfr", "-frames:v", str(max_frames), "-q:v", "3",
              str(outdir / "%03d.jpg")])
        frames = sorted(outdir.glob("*.jpg"))
        if not _nonempty(frames):  # static video: fall back to uniform sampling
            return video_frames(path, n=max_frames, width=width)
    return _nonempty(frames)


# --- audio clip (native listening) ----------------------------------------
def audio_clip_mp3(path: Path, start: float = 0.0, dur: float = 90.0) -> str:
    """Downsampled mono mp3 clip as base64 (small enough to attach)."""
    out = config.CACHE / f"clip_{_hash(path, start, dur)}.mp3"
    if not out.exists():
        _run(["ffmpeg", "-y", "-ss", f"{start:.2f}", "-t", f"{dur:.2f}",
              "-i", str(path), "-ac", "1", "-ar", "16000", "-b:a", "48k", str(out)])
    return base64.b64encode(out.read_bytes()).decode()


# --- transcription (the degraded audio path available to every judge) ------
def _extract_wav(path: Path) -> Path:
    out = config.CACHE / f"audio_{_hash(path)}.mp3"
    if not out.exists():
        _run(["ffmpeg", "-y", "-i", str(path), "-ac", "1", "-ar", "16000",
              "-b:a", "48k", out.as_posix()])
    return out


def transcribe(path: Path, max_seconds: float = 600.0) -> str:
    """Whisper transcript, cached. Caps very long media to bound cost."""
    cache = config.CACHE / f"transcript_{_hash(path, max_seconds)}.txt"
    if cache.exists():
        return cache.read_text()
    audio = _extract_wav(path)
    # Trim to the cap so a 30-min stem set doesn't blow the budget.
    dur = duration_seconds(audio)
    if dur > max_seconds:
        trimmed = config.CACHE / f"trim_{_hash(audio, max_seconds)}.mp3"
        if not trimmed.exists():
            _run(["ffmpeg", "-y", "-t", f"{max_seconds}", "-i", str(audio), str(trimmed)])
        audio = trimmed
    try:
        with open(audio, "rb") as fh:
            r = _openai().audio.transcriptions.create(model="whisper-1", file=fh)
        text = r.text
    except Exception as e:
        text = f"[transcription failed: {e}]"
    cache.write_text(text)
    return text

